@page "/privacy"
@using Microsoft.AspNetCore.Http
@attribute [ExcludeFromInteractiveRouting]

<PageTitle>Privacy Policy</PageTitle>

<h1>Privacy Policy</h1>

<p>
    This application collects minimal data necessary to provide its services.
    We respect your privacy and are committed to protecting your personal information.
</p>

<h2>Cookies</h2>
<p>
    We use cookies to improve your experience. By using this site, you consent
    to our use of cookies in accordance with this policy.
</p>

@if (HasConsented)
{
    <div class="alert alert-success mt-3">
        <strong>✓ You have already accepted cookies.</strong>
    </div>
}
else
{
    <div class="alert alert-warning mt-3">
        <strong>You have not yet accepted cookies.</strong>
    </div>
}

@code {
    [CascadingParameter]
    private HttpContext? HttpContext { get; set; }

    private bool HasConsented { get; set; }

    protected override void OnInitialized()
    {
        HasConsented = HttpContext?.Request.Cookies.ContainsKey("consent") == true;
    }
}

